using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public enum TowerState
    {
        Idle,
        Targeting,
        Attacking,
        Upgrading,
        Selling
    }

    public class Tower : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] protected TowerData _towerData;
        [SerializeField] protected TowerAttack _attack;
        [SerializeField] protected Animator _animator;
        [SerializeField] protected Transform _rotatePart;
        [SerializeField] protected SpriteRenderer _spriteRenderer;

        [Header("Visual")]
        [SerializeField] protected GameObject _rangeIndicator;
        [SerializeField] protected Color _rangeColor = new Color(0, 1, 0, 0.3f);
        [Tooltip("Rotation offset in degrees. Default -90 assumes sprite faces UP. Change to 0 if sprite faces RIGHT.")]
        [SerializeField] protected float _rotationOffset = -90f;

        protected int _currentLevel = 1;
        protected TowerState _currentState = TowerState.Idle;
        protected TowerData.TowerStats _currentStats;
        protected Enemy.Enemy _currentTarget;
        protected TowerSlot _slot;

        public TowerData Data => _towerData;
        public int CurrentLevel => _currentLevel;
        public TowerState State => _currentState;
        public Enemy.Enemy CurrentTarget => _currentTarget;
        public TowerData.TowerStats CurrentStats => _currentStats;
        public TowerSlot Slot => _slot;
        public bool IsMaxLevel => _currentLevel >= _towerData.levels.Length;

        public System.Action<Tower> OnUpgrade;
        public System.Action<Tower> OnSell;
        public System.Action<Enemy.Enemy> OnTargetAcquired;
        public System.Action OnTargetLost;

        protected virtual void Awake()
        {
            if (_attack == null) _attack = GetComponent<TowerAttack>();
            if (_animator == null) _animator = GetComponentInChildren<Animator>();
        }

        public virtual void Initialize(TowerData data, TowerSlot slot)
        {
            _towerData = data;
            _slot = slot;
            _currentLevel = 1;
            _currentStats = data.levels[0];
            _currentState = TowerState.Idle;

            if (_attack != null)
            {
                _attack.Initialize(this);
            }

            UpdateRangeIndicator();
        }

        protected virtual void Update()
        {
            if (_currentState == TowerState.Upgrading || _currentState == TowerState.Selling)
                return;

            FindTarget();

            if (_currentTarget != null)
            {
                RotateTowardsTarget();
                Attack();
            }
        }

        protected virtual void FindTarget()
        {
            float actualAttackRange = _attack != null ? _attack.GetEffectiveAttackRange() : _currentStats.attackRange;

            if (_currentTarget != null && !_currentTarget.IsDead)
            {
                float distance = Vector3.Distance(transform.position, _currentTarget.transform.position);
                if (distance <= actualAttackRange)
                {
                    return;
                }
            }

            _currentTarget = FindBestTarget();

            if (_currentTarget != null)
            {
                _currentState = TowerState.Targeting;
                OnTargetAcquired?.Invoke(_currentTarget);
            }
            else
            {
                _currentState = TowerState.Idle;
                OnTargetLost?.Invoke();
            }
        }

        protected virtual Enemy.Enemy FindBestTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null)
            {
                Debug.LogError("EnemySpawner not found!");
                return null;
            }

            float actualAttackRange = _attack != null ? _attack.GetEffectiveAttackRange() : _currentStats.attackRange;
            List<Enemy.Enemy> enemiesInRange = spawner.GetEnemiesInRange(transform.position, actualAttackRange);

            if (enemiesInRange.Count == 0) return null;

            Enemy.Enemy bestTarget = null;
            float bestPriority = float.MinValue;

            foreach (var enemy in enemiesInRange)
            {
                if (enemy == null || enemy.IsDead) continue;

                float priority = CalculateTargetPriority(enemy);
                if (priority > bestPriority)
                {
                    bestPriority = priority;
                    bestTarget = enemy;
                }
            }

            return bestTarget;
        }

        protected virtual float CalculateTargetPriority(Enemy.Enemy enemy)
        {
            EnemyMovement movement = enemy.GetComponent<EnemyMovement>();
            if (movement != null)
            {
                return movement.GetProgressPercent();
            }
            return 0f;
        }

        protected virtual void RotateTowardsTarget()
        {
            if (_currentTarget == null) return;
            if (_towerData != null && (_towerData.towerType == TowerType.Barracks || _towerData.towerType == TowerType.Mage)) return;

            Transform rotateTransform = GetRotateTransform();
            if (rotateTransform == null) return;

            Vector3 direction = _currentTarget.transform.position - rotateTransform.position;
            float angle = Mathf.Atan2(direction.y, direction.x) * Mathf.Rad2Deg + _rotationOffset;
            Quaternion targetRotation = Quaternion.AngleAxis(angle, Vector3.forward);
            rotateTransform.rotation = Quaternion.Slerp(rotateTransform.rotation, targetRotation, 10f * Time.deltaTime);
        }

        /// <summary>
        /// Returns the transform that should rotate towards the target.
        /// Uses _rotatePart if it has a visual (renderer in children), 
        /// otherwise falls back to the sprite renderer's transform.
        /// </summary>
        protected Transform GetRotateTransform()
        {
            if (_rotatePart != null)
            {
                if (_rotatePart.GetComponent<Renderer>() != null || _rotatePart.GetComponentInChildren<Renderer>() != null)
                    return _rotatePart;
            }

            if (_spriteRenderer != null)
                return _spriteRenderer.transform;

            var sr = GetComponent<SpriteRenderer>();
            if (sr != null)
                return sr.transform;

            return _rotatePart;
        }

        protected virtual void Attack()
        {
            if (_attack == null) return;

            if (_attack.CanAttack())
            {
                _currentState = TowerState.Attacking;
                _attack.Attack(_currentTarget);
            }
        }

        public virtual bool Upgrade()
        {
            if (IsMaxLevel) return false;

            TowerData.TowerStats nextLevelStats = _towerData.levels[_currentLevel];
            if (!GameManager.Instance.SpendGold(nextLevelStats.upgradeCost)) return false;

            _currentLevel++;
            _currentStats = nextLevelStats;

            if (_animator != null)
            {
                _animator.SetTrigger("Upgrade");
            }

            UpdateRangeIndicator();
            OnUpgrade?.Invoke(this);
            EventBus.Publish(new TowerUpgradedEvent { Tower = gameObject, Level = _currentLevel });

            return true;
        }

        public virtual void Sell()
        {
            Debug.Log($"📤 Tower.Sell() called for {gameObject.name}");
            Debug.Log($"   sellValue: {_currentStats.sellValue}");
            Debug.Log($"   _slot: {_slot != null}");

            int sellValue = _currentStats.sellValue;
            GameManager.Instance.AddGold(sellValue);
            Debug.Log($"   ✅ Added {sellValue} gold");

            OnSell?.Invoke(this);
            EventBus.Publish(new TowerSoldEvent { Tower = gameObject, Refund = sellValue });

            if (_slot != null)
            {
                _slot.RemoveTower();
                Debug.Log($"   ✅ Called _slot.RemoveTower()");
            }

            Destroy(gameObject);
            Debug.Log($"   ✅ Tower destroyed");
        }

        public int GetUpgradeCost()
        {
            if (IsMaxLevel) return 0;
            return _towerData.levels[_currentLevel].upgradeCost;
        }

        public int GetSellValue()
        {
            return _currentStats.sellValue;
        }

        public void ShowRange()
        {
            if (_rangeIndicator != null)
            {
                _rangeIndicator.SetActive(true);
            }
        }

        public void HideRange()
        {
            if (_rangeIndicator != null)
            {
                _rangeIndicator.SetActive(false);
            }
        }

        protected void UpdateRangeIndicator()
        {
            if (_rangeIndicator != null)
            {
                float scale = _currentStats.attackRange * 2f;
                _rangeIndicator.transform.localScale = new Vector3(scale, scale, 1f);
            }
        }

        private void OnDrawGizmosSelected()
        {
            if (_towerData != null && _currentStats.attackRange > 0)
            {
                Gizmos.color = _rangeColor;
                Gizmos.DrawWireSphere(transform.position, _currentStats.attackRange);
            }
        }
    }
}

using System;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 家园主控制器，管理家园场景的初始化和生命周期。
    /// 作为 GameModule 注册到 ModuleManager。
    /// </summary>
    public class HomeManager : GameModule
    {
        private const string MODULE_ID = "home";
        private const string MODULE_DISPLAY_NAME = "家园";
        private const string SAVE_KEY = "homebase";

        [Header("组件引用")]
        [SerializeField] private BuildingManager _buildingManager;
        [SerializeField] private ResourceManager _resourceManager;

        [Header("初始建筑")]
        [SerializeField] private BuildingData[] _starterBuildings;
        [SerializeField] private Vector3[] _starterPositions;

        private bool _isLoaded = false;

        private void Awake()
        {
            _moduleId = MODULE_ID;
            _displayName = MODULE_DISPLAY_NAME;
            _sceneName = gameObject.scene.name;
        }

        private void Start()
        {
            InitializeHome();
        }

        private void InitializeHome()
        {
            if (_isLoaded) return;

            // 注册到 ModuleManager
            var moduleManager = ModuleManager.Instance;
            if (moduleManager != null)
            {
                moduleManager.RegisterModule(this);
            }

            // 尝试从存档加载
            LoadHomeSave();

            // 如果没有建筑，放置初始建筑
            if (_buildingManager.Buildings.Count == 0)
            {
                PlaceStarterBuildings();
            }

            _isLoaded = true;
            Debug.Log("[HomeManager] 家园初始化完成");
        }

        private void PlaceStarterBuildings()
        {
            if (_starterBuildings == null || _starterPositions == null) return;

            int count = Mathf.Min(_starterBuildings.Length, _starterPositions.Length);
            for (int i = 0; i < count; i++)
            {
                if (_starterBuildings[i] != null)
                {
                    _buildingManager.PlaceBuilding(_starterBuildings[i], _starterPositions[i]);
                }
            }

            Debug.Log($"[HomeManager] 放置 {count} 个初始建筑");
        }

        #region 存档

        public override string GetModuleSaveData()
        {
            var saveData = new HomeSaveData();
            _resourceManager?.SaveToSave(saveData);
            saveData.buildings = _buildingManager?.ExportSaveData();
            return JsonUtility.ToJson(saveData);
        }

        public override void RestoreModuleSaveData(string jsonData)
        {
            if (string.IsNullOrEmpty(jsonData)) return;

            try
            {
                var saveData = JsonUtility.FromJson<HomeSaveData>(jsonData);
                _resourceManager?.LoadFromSave(saveData);
                _buildingManager?.RestoreFromSaveData(saveData.buildings);
            }
            catch (Exception e)
            {
                Debug.LogError($"[HomeManager] 恢复存档失败: {e.Message}");
            }
        }

        private void LoadHomeSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = saveSystem.LoadModuleData(SAVE_KEY);
            if (!string.IsNullOrEmpty(json))
            {
                RestoreModuleSaveData(json);
                Debug.Log("[HomeManager] 家园存档已加载");
            }
        }

        private void SaveHomeData()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = GetModuleSaveData();
            saveSystem.SaveModuleData(SAVE_KEY, json, 1);
        }

        #endregion

        #region 模块生命周期

        public override void Activate()
        {
            base.Activate();
            Debug.Log("[HomeManager] 家园已激活");
        }

        public override void Deactivate()
        {
            SaveHomeData();
            base.Deactivate();
            Debug.Log("[HomeManager] 家园已停用");
        }

        #endregion

        #region 按钮回调

        /// <summary>
        /// 收集所有资源按钮回调。
        /// </summary>
        public void OnCollectAllClicked()
        {
            _resourceManager?.CollectAllResources();
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) SaveHomeData();
        }

        private void OnApplicationQuit()
        {
            SaveHomeData();
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class GameUI : MonoBehaviour
    {
        [Header("Top Bar")]
        [SerializeField] private Image _goldIcon;
        [SerializeField] private Text _goldText;
        [SerializeField] private Image _lifeIcon;
        [SerializeField] private Text _lifeText;
        [SerializeField] private Image _waveIcon;
        [SerializeField] private Text _waveText;

        [Header("Wave Info")]
        [SerializeField] private GameObject _waveInfoPanel;
        [SerializeField] private Text _waveTimerText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Button _startWaveButton;

        [Header("Tower Selection")]
        [SerializeField] private GameObject _towerSelectPanel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;

        [Header("Tower Info")]
        [SerializeField] private GameObject _towerInfoPanel;
        [SerializeField] private Text _towerNameText;
        [SerializeField] private Text _towerLevelText;
        [SerializeField] private Text _towerDamageText;
        [SerializeField] private Button _upgradeButton;
        [SerializeField] private Text _upgradeCostText;
        [SerializeField] private Button _sellButton;
        [SerializeField] private Text _sellValueText;

        [Header("Game Controls")]
        [SerializeField] private Button _pauseButton;
        [SerializeField] private Button _speedButton;
        [SerializeField] private GameObject _pauseMenu;
        [SerializeField] private GameObject _gameOverPanel;
        [SerializeField] private GameObject _victoryPanel;

        [Header("Settings")]
        [SerializeField] private Slider _volumeSlider;
        [SerializeField] private Toggle _soundToggle;

        private Tower.TowerSlot _selectedSlot;
        private Tower.Tower _selectedTower;

        private void Start()
        {
            InitializeUI();
            SubscribeToEvents();
        }

        private void InitializeUI()
        {
            if (_pauseMenu != null) _pauseMenu.SetActive(false);
            if (_gameOverPanel != null) _gameOverPanel.SetActive(false);
            if (_victoryPanel != null) _victoryPanel.SetActive(false);
            if (_towerInfoPanel != null) _towerInfoPanel.SetActive(false);
            if (_towerSelectPanel != null) _towerSelectPanel.SetActive(false);

            UpdateGoldDisplay(GameManager.Instance.CurrentGold);
            UpdateLifeDisplay(GameManager.Instance.CurrentLife);
            UpdateWaveDisplay(GameManager.Instance.CurrentWave);

            if (_startWaveButton != null)
            {
                _startWaveButton.onClick.AddListener(OnStartWaveClicked);
            }
            if (_pauseButton != null)
            {
                _pauseButton.onClick.AddListener(OnPauseClicked);
            }
            if (_speedButton != null)
            {
                _speedButton.onClick.AddListener(OnSpeedClicked);
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.onClick.AddListener(OnUpgradeClicked);
            }
            if (_sellButton != null)
            {
                _sellButton.onClick.AddListener(OnSellClicked);
            }
        }

        private void SubscribeToEvents()
        {
            GameManager.Instance.OnGoldChanged += UpdateGoldDisplay;
            GameManager.Instance.OnLifeChanged += UpdateLifeDisplay;
            GameManager.Instance.OnWaveChanged += UpdateWaveDisplay;
            GameManager.Instance.OnStateChanged += OnGameStateChanged;

            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Subscribe<LifeChangedEvent>(OnLifeChanged);
        }

        private void OnDestroy()
        {
            if (GameManager.Instance != null)
            {
                GameManager.Instance.OnGoldChanged -= UpdateGoldDisplay;
                GameManager.Instance.OnLifeChanged -= UpdateLifeDisplay;
                GameManager.Instance.OnWaveChanged -= UpdateWaveDisplay;
                GameManager.Instance.OnStateChanged -= OnGameStateChanged;
            }

            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Unsubscribe<LifeChangedEvent>(OnLifeChanged);
        }

        #region Display Updates

        private void UpdateGoldDisplay(int gold)
        {
            if (_goldText != null)
            {
                _goldText.text = gold.ToString();
            }

            if (_goldIcon != null)
            {
                _goldIcon.enabled = true;
            }
        }

        private void UpdateLifeDisplay(int life)
        {
            if (_lifeText != null)
            {
                _lifeText.text = life.ToString();
            }

            if (_lifeIcon != null)
            {
                _lifeIcon.enabled = true;
            }
        }

        private void UpdateWaveDisplay(int wave)
        {
            if (_waveText != null)
            {
                _waveText.text = $"{wave}/{GameManager.Instance.TotalWaves}";
            }

            if (_waveIcon != null)
            {
                _waveIcon.enabled = true;
            }
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateGoldDisplay(e.CurrentGold);
        }

        private void OnLifeChanged(LifeChangedEvent e)
        {
            UpdateLifeDisplay(e.CurrentLife);
        }

        #endregion

        #region Tower Selection

        public void ShowTowerSelectPanel(Tower.TowerSlot slot)
        {
            _selectedSlot = slot;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(true);
            }
        }

        public void HideTowerSelectPanel()
        {
            _selectedSlot = null;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(false);
            }
        }

        public void SelectTower(Data.TowerData towerData)
        {
            if (_selectedSlot != null)
            {
                _selectedSlot.PlaceTower(towerData);
                HideTowerSelectPanel();
            }
        }

        #endregion

        #region Tower Info

        public void ShowTowerInfo(Tower.Tower tower)
        {
            _selectedTower = tower;

            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(true);
            }

            UpdateTowerInfo();
        }

        public void HideTowerInfo()
        {
            _selectedTower = null;
            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(false);
            }
        }

        private void UpdateTowerInfo()
        {
            if (_selectedTower == null) return;

            if (_towerNameText != null)
            {
                _towerNameText.text = _selectedTower.Data.towerName;
            }
            if (_towerLevelText != null)
            {
                _towerLevelText.text = $"Level: {_selectedTower.CurrentLevel}";
            }
            if (_towerDamageText != null)
            {
                _towerDamageText.text = $"Damage: {_selectedTower.CurrentStats.damage}";
            }
            if (_upgradeCostText != null)
            {
                int cost = _selectedTower.GetUpgradeCost();
                _upgradeCostText.text = cost > 0 ? cost.ToString() : "MAX";
            }
            if (_sellValueText != null)
            {
                _sellValueText.text = _selectedTower.GetSellValue().ToString();
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.interactable = !_selectedTower.IsMaxLevel;
            }
        }

        #endregion

        #region Button Handlers

        private void OnStartWaveClicked()
        {
            Wave.WaveManager waveManager = FindObjectOfType<Wave.WaveManager>();
            if (waveManager != null)
            {
                waveManager.ForceStartWave();
            }

            if (_startWaveButton != null)
            {
                _startWaveButton.gameObject.SetActive(false);
            }
        }

        private void OnPauseClicked()
        {
            GameManager.Instance.TogglePause();

            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(GameManager.Instance.CurrentState == GameState.Paused);
            }
        }

        private void OnSpeedClicked()
        {
            float currentSpeed = GameManager.Instance.GameSpeed;
            float newSpeed = currentSpeed >= 3f ? 1f : currentSpeed + 1f;

            if (_speedButton != null)
            {
                Text textComponent = _speedButton.GetComponentInChildren<Text>();
                if (textComponent != null)
                {
                    textComponent.text = $"{newSpeed}x";
                }
            }
        }

        private void OnUpgradeClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Upgrade();
                UpdateTowerInfo();
            }
        }

        private void OnSellClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Sell();
                HideTowerInfo();
            }
        }

        #endregion

        #region Game State

        private void OnGameStateChanged(GameState state)
        {
            switch (state)
            {
                case GameState.Paused:
                    ShowPauseMenu();
                    break;
                case GameState.Playing:
                    HidePauseMenu();
                    break;
                case GameState.GameOver:
                    ShowGameOver();
                    break;
                case GameState.Victory:
                    ShowVictory();
                    break;
            }
        }

        private void ShowPauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(true);
            }
        }

        private void HidePauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(false);
            }
        }

        private void ShowGameOver()
        {
            if (_gameOverPanel != null)
            {
                _gameOverPanel.SetActive(true);
            }
        }

        private void ShowVictory()
        {
            if (_victoryPanel != null)
            {
                _victoryPanel.SetActive(true);
            }
        }

        #endregion

        #region Wave Timer

        public void UpdateWaveTimer(float time)
        {
            if (_waveTimerText != null)
            {
                if (time > 0)
                {
                    _waveTimerText.text = $"Next Wave: {Mathf.CeilToInt(time)}s";
                }
                else
                {
                    _waveTimerText.text = "Wave In Progress";
                }
            }
        }

        public void UpdateEnemyCount(int count)
        {
            if (_enemyCountText != null)
            {
                _enemyCountText.text = $"Enemies: {count}";
            }
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class TowerInfoPanel : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] private GameObject _panel;

        [Header("Tower Info")]
        [SerializeField] private Text _towerNameText;
        [SerializeField] private Text _towerLevelText;
        [SerializeField] private Text _damageText;
        [SerializeField] private Text _rangeText;
        [SerializeField] private Text _attackSpeedText;

        [Header("Buttons")]
        [SerializeField] private Button _upgradeButton;
        [SerializeField] private Text _upgradeCostText;
        [SerializeField] private Button _sellButton;
        [SerializeField] private Text _sellValueText;
        [SerializeField] private Button _closeButton;

        private TowerDefense.Tower.Tower _currentTower;

        private void Awake()
        {
            if (_panel != null)
            {
                _panel.SetActive(false);
            }

            if (_upgradeButton != null)
            {
                _upgradeButton.onClick.AddListener(OnUpgradeClicked);
            }

            if (_sellButton != null)
            {
                _sellButton.onClick.AddListener(OnSellClicked);
            }

            if (_closeButton != null)
            {
                _closeButton.onClick.AddListener(Hide);
            }
        }

        public void Show(TowerDefense.Tower.Tower tower)
        {
            _currentTower = tower;

            UpdateTowerInfo();

            if (_panel != null)
            {
                _panel.SetActive(true);
            }

            tower.OnUpgrade += OnTowerUpgraded;
            tower.OnSell += OnTowerSold;
        }

        public void Hide()
        {
            if (_currentTower != null)
            {
                _currentTower.OnUpgrade -= OnTowerUpgraded;
                _currentTower.OnSell -= OnTowerSold;
            }

            _currentTower = null;

            if (_panel != null)
            {
                _panel.SetActive(false);
            }
        }

        private void UpdateTowerInfo()
        {
            if (_currentTower == null) return;

            var data = _currentTower.Data;
            var stats = _currentTower.CurrentStats;

            if (_towerNameText != null)
            {
                _towerNameText.text = data.towerName;
            }

            if (_towerLevelText != null)
            {
                _towerLevelText.text = $"等级 {_currentTower.CurrentLevel}/{data.levels.Length}";
            }

            if (_damageText != null)
            {
                _damageText.text = $"伤害: {stats.damage}";
            }

            if (_rangeText != null)
            {
                _rangeText.text = $"攻击范围: {stats.attackRange}";
            }

            if (_attackSpeedText != null)
            {
                _attackSpeedText.text = $"攻击速度: {stats.attackSpeed:0.0}";
            }

            UpdateUpgradeButton();
            UpdateSellButton();
        }

        private void UpdateUpgradeButton()
        {
            if (_upgradeButton == null || _upgradeCostText == null) return;

            if (_currentTower.IsMaxLevel)
            {
                _upgradeButton.interactable = false;
                _upgradeCostText.text = "已满级";
                _upgradeCostText.color = Color.grey;
            }
            else
            {
                int upgradeCost = _currentTower.GetUpgradeCost();
                bool canAfford = GameManager.Instance.HasEnoughGold(upgradeCost);

                _upgradeButton.interactable = canAfford;
                _upgradeCostText.text = $"升级（{upgradeCost}金币）";
                _upgradeCostText.color = canAfford ? Color.yellow : Color.red;
            }
        }

        private void UpdateSellButton()
        {
            if (_sellValueText == null) return;

            int sellValue = _currentTower.GetSellValue();
            _sellValueText.text = $"出售（{sellValue}金币）";
        }

        private void OnUpgradeClicked()
        {
            if (_currentTower != null)
            {
                _currentTower.Upgrade();
            }
        }

        private void OnSellClicked()
        {
            if (_currentTower != null)
            {
                _currentTower.Sell();
            }
        }

        private void OnTowerUpgraded(TowerDefense.Tower.Tower tower)
        {
            UpdateTowerInfo();
        }

        private void OnTowerSold(TowerDefense.Tower.Tower tower)
        {
            Hide();
        }

        private void OnEnable()
        {
            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnDisable()
        {
            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            if (_panel != null && _panel.activeSelf && _currentTower != null)
            {
                UpdateUpgradeButton();
            }
        }
    }
}

using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Save;

namespace TowerDefense.Data
{
    public class PlayerLevelSystem : Singleton<PlayerLevelSystem>
    {
        [Header("等级配置")]
        [SerializeField] private int _maxLevel = 99;
        [SerializeField] private int _baseExp = 100;
        [SerializeField] private int _expIncrement = 50;

        private int _level = 1;
        private int _currentExp = 0;

        /// <summary>是否代理到共享 PlayerProfile</summary>
        private bool _isProxyMode;

        private Sttop5.Shared.Player.PlayerProfile _profile;

        public int Level => _isProxyMode ? GetProxyLevel() : _level;
        public int CurrentExp => _isProxyMode ? GetProxyExp() : _currentExp;
        public int MaxLevel => _maxLevel;
        public int ExpToNextLevel => _isProxyMode ? GetProxyExpToNext() : GetExpRequiredForLevel(_level);
        public float ExpProgress => Level >= _maxLevel ? 1f : (float)CurrentExp / ExpToNextLevel;
        public bool IsMaxLevel => Level >= _maxLevel;

        public event System.Action<int> OnLevelChanged;
        public event System.Action<int, int> OnExpChanged;

        private bool _loadedFromSave = false;

        protected override void Awake()
        {
            base.Awake();
        }

        private void Start()
        {
            // 检测模块模式（通过场景名或全局标志判断）
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "TDGameScene" || ModuleModeDetector.IsModuleMode)
            {
                EnableProxyMode();
            }
            else
            {
                LoadFromSave();
            }
        }

        /// <summary>
        /// 启用代理模式，将等级/经验操作转发到共享 PlayerProfile。
        /// </summary>
        public void EnableProxyMode()
        {
            _profile = Sttop5.Shared.Player.PlayerProfile.Instance;
            if (_profile != null)
            {
                _isProxyMode = true;
                _level = _profile.Level;
                _currentExp = _profile.CurrentExp;

                _profile.OnLevelChanged += OnProxyLevelChanged;
                _profile.OnExpChanged += OnProxyExpChanged;

                Debug.Log($"[PlayerLevelSystem] 代理模式已启用: Lv.{_level}");
            }
            else
            {
                LoadFromSave();
                Debug.LogWarning("[PlayerLevelSystem] PlayerProfile 不可用，使用独立模式");
            }
        }

        /// <summary>
        /// 禁用代理模式。
        /// </summary>
        public void DisableProxyMode()
        {
            if (_profile != null)
            {
                _profile.OnLevelChanged -= OnProxyLevelChanged;
                _profile.OnExpChanged -= OnProxyExpChanged;
            }
            _isProxyMode = false;
            _profile = null;
        }

        #region Proxy Helpers

        private int GetProxyLevel() => _profile != null ? _profile.Level : _level;
        private int GetProxyExp() => _profile != null ? _profile.CurrentExp : _currentExp;
        private int GetProxyExpToNext() => _profile != null ? _profile.ExpToNextLevel : GetExpRequiredForLevel(_level);

        private void OnProxyLevelChanged(int level)
        {
            _level = level;
            OnLevelChanged?.Invoke(level);
        }

        private void OnProxyExpChanged(int currentExp, int expToNext)
        {
            _currentExp = currentExp;
            OnExpChanged?.Invoke(currentExp, expToNext);
            EventBus.Publish(new ExpChangedEvent { Level = _level, CurrentExp = currentExp, ExpToNext = expToNext });
        }

        #endregion

        public int GetExpRequiredForLevel(int level)
        {
            if (level >= _maxLevel) return int.MaxValue;
            return _baseExp + (level - 1) * _expIncrement;
        }

        public void AddExp(int amount)
        {
            if (amount <= 0 || IsMaxLevel) return;

            if (_isProxyMode && _profile != null)
            {
                _profile.AddExp(amount);
                return;
            }

            if (!_loadedFromSave)
            {
                LoadFromSave();
            }

            int oldLevel = _level;
            _currentExp += amount;

            while (_currentExp >= ExpToNextLevel && !IsMaxLevel)
            {
                _currentExp -= ExpToNextLevel;
                _level++;
            }

            if (IsMaxLevel)
                _currentExp = 0;

            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
            EventBus.Publish(new ExpChangedEvent { Level = _level, CurrentExp = _currentExp, ExpToNext = ExpToNextLevel });

            if (_level != oldLevel)
            {
                OnLevelChanged?.Invoke(_level);
                EventBus.Publish(new LevelUpEvent { NewLevel = _level, OldLevel = oldLevel });
                Debug.Log($"[PlayerLevelSystem] 升级! Lv.{oldLevel} → Lv.{_level}");
            }
        }

        public void SetLevelData(int level, int exp)
        {
            _level = Mathf.Clamp(level, 1, _maxLevel);
            _currentExp = IsMaxLevel ? 0 : Mathf.Clamp(exp, 0, ExpToNextLevel);
            OnLevelChanged?.Invoke(_level);
            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
        }

        private void LoadFromSave()
        {
            var save = SaveSystem.Instance;
            if (save != null && save.CurrentSave != null)
            {
                var player = save.CurrentSave.player;
                SetLevelData(player.playerLevel, player.playerExp);
                _loadedFromSave = true;
                Debug.Log($"[PlayerLevelSystem] 从存档加载: Lv.{_level}, Exp={_currentExp}");
            }
            else
            {
                Debug.LogWarning("[PlayerLevelSystem] SaveSystem 未就绪，将在首次 AddExp 时重试加载");
            }
        }

        public void PersistToSave()
        {
            if (_isProxyMode)
            {
                // 代理模式下由 PlayerProfile 自己持久化
                _profile?.PersistToSave();
                return;
            }

            var save = SaveSystem.Instance;
            if (save != null && save.CurrentSave != null)
            {
                save.CurrentSave.player.playerLevel = _level;
                save.CurrentSave.player.playerExp = _currentExp;
                save.SaveGame();
            }
        }

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) PersistToSave();
        }

        private void OnApplicationQuit()
        {
            PersistToSave();
        }

        private void OnDisable()
        {
            PersistToSave();
        }

        private new void OnDestroy()
        {
            DisableProxyMode();
        }
    }
}

