{
    /// <summary>
    /// 建筑存档数据。
    /// </summary>
    [Serializable]
    public class BuildingSaveEntry
    {
        public string buildingId;
        public float posX;
        public float posY;
        public int level;
    }

    /// <summary>
    /// 家园存档数据。
    /// </summary>
    [Serializable]
    public class HomeSaveData
    {
        public int wood;
        public int stone;
        public int food;
        public List<BuildingSaveEntry> buildings = new List<BuildingSaveEntry>();
    }

    /// <summary>
    /// 建筑管理器，负责建筑的放置、升级和拆除。
    /// </summary>
    public class BuildingManager : MonoBehaviour
    {
        [Header("建筑配置列表")]
        [SerializeField] private BuildingData[] _availableBuildings;

        private List<BuildingBase> _buildings = new List<BuildingBase>();

        public BuildingData[] AvailableBuildings => _availableBuildings;
        public IReadOnlyList<BuildingBase> Buildings => _buildings;

        #region 放置与检测

        /// <summary>
        /// 在指定世界坐标放置建筑。
        /// </summary>
        public BuildingBase PlaceBuilding(BuildingData data, Vector3 worldPos)
        {
            // 扣除建造费用
            var levelData = data.GetLevelData(1);
            var profile = PlayerProfile.Instance;
            if (profile != null && levelData.buildCost > 0 && !profile.HasEnoughGold(levelData.buildCost))
            {
                Debug.LogWarning("[BuildingManager] 金币不足");
                return null;
            }
            profile?.SpendGold(levelData.buildCost, "building_place");

            // 实例化建筑
            GameObject go = data.prefab != null
                ? Instantiate(data.prefab, worldPos, Quaternion.identity, transform)
                : CreatePlaceholderBuilding(data, worldPos);

            BuildingBase building = go.GetComponent<BuildingBase>();
            if (building == null)
                building = go.AddComponent<BuildingBase>();

            building.Initialize(data);
            _buildings.Add(building);
            Debug.Log($"[BuildingManager] 建筑已放置: {data.buildingName} at {worldPos}");
            return building;
        }

        /// <summary>
        /// 拆除指定建筑。
        /// </summary>
        public bool RemoveBuilding(BuildingBase building)
        {
            if (building == null || !_buildings.Contains(building))
                return false;

            _buildings.Remove(building);
            building.Demolish();
            return true;
        }

        /// <summary>
        /// 获取指定位置附近的建筑。
        /// </summary>
        public BuildingBase GetBuildingNear(Vector3 worldPos, float radius = 1f)
        {
            float minDist = float.MaxValue;
            BuildingBase nearest = null;
            foreach (var b in _buildings)
            {
                if (b == null) continue;
                float dist = Vector3.Distance(b.transform.position, worldPos);
                if (dist < radius && dist < minDist)
                {
                    minDist = dist;
                    nearest = b;
                }
            }
            return nearest;
        }

        #endregion

        #region 存档

        /// <summary>
        /// 导出所有建筑的存档数据。
        /// </summary>
        public List<BuildingSaveEntry> ExportSaveData()
        {
            var result = new List<BuildingSaveEntry>();
            foreach (var building in _buildings)
            {
                if (building == null) continue;
                result.Add(new BuildingSaveEntry
                {
                    buildingId = building.Data.buildingId,
                    posX = building.transform.position.x,
                    posY = building.transform.position.y,
                    level = building.CurrentLevel
                });
            }
            return result;
        }

        /// <summary>
        /// 从存档数据恢复所有建筑。
        /// </summary>
        public void RestoreFromSaveData(List<BuildingSaveEntry> entries)
        {
            if (entries == null) return;

            foreach (var entry in entries)
            {
                BuildingData data = FindBuildingData(entry.buildingId);
                if (data == null)
                {
                    Debug.LogWarning($"[BuildingManager] 未找到建筑配置: {entry.buildingId}");
                    continue;
                }

                Vector3 worldPos = new Vector3(entry.posX, entry.posY, 0f);
                GameObject go = data.prefab != null
                    ? Instantiate(data.prefab, worldPos, Quaternion.identity, transform)
                    : CreatePlaceholderBuilding(data, worldPos);

                BuildingBase building = go.GetComponent<BuildingBase>();
                if (building == null)
                    building = go.AddComponent<BuildingBase>();

                building.RestoreFromSave(data, entry.level);
                _buildings.Add(building);
            }

            Debug.Log($"[BuildingManager] 从存档恢复 {entries.Count} 个建筑");
        }

        #endregion

        #region 辅助

        private BuildingData FindBuildingData(string buildingId)
        {
            if (_availableBuildings == null) return null;
            foreach (var data in _availableBuildings)
            {
                if (data.buildingId == buildingId)
                    return data;
            }
            return null;
        }

        private GameObject CreatePlaceholderBuilding(BuildingData data, Vector3 worldPos)
        {
            GameObject go = new GameObject($"Building_{data.buildingName}");
            go.transform.position = worldPos;
            go.transform.SetParent(transform);

            SpriteRenderer sr = go.AddComponent<SpriteRenderer>();
            sr.sprite = data.icon;
            if (sr.sprite == null)
            {
                sr.color = GetBuildingColor(data.buildingType);
            }
            sr.sortingOrder = 10;

            return go;
        }

        private Color GetBuildingColor(BuildingType type)
        {
            switch (type)
            {
                case BuildingType.ResourceGen: return new Color(0.2f, 0.8f, 0.3f);
                case BuildingType.Portal: return new Color(0.3f, 0.5f, 1f);
                case BuildingType.Storage: return new Color(0.9f, 0.7f, 0.2f);
                case BuildingType.Decoration: return new Color(0.9f, 0.4f, 0.7f);
                case BuildingType.Special: return new Color(1f, 0.5f, 0.1f);
                default: return Color.white;
            }
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using UnityEngine.SceneManagement;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class VictoryPanel : MonoBehaviour
    {
        [Header("Title")]
        [SerializeField] private Text _titleText;

        [Header("Stars")]
        [SerializeField] private Image[] _starImages = new Image[3];
        [SerializeField] private Sprite _starFilledSprite;
        [SerializeField] private Sprite _starEmptySprite;

        [Header("Stats")]
        [SerializeField] private Text _killCountText;
        [SerializeField] private Text _goldText;
        [SerializeField] private Text _waveText;

        [Header("Buttons")]
        [SerializeField] private Button _restartButton;
        [SerializeField] private Button _nextLevelButton;
        [SerializeField] private Button _mainMenuButton;

        private void Awake()
        {
            if (_restartButton != null)
                _restartButton.onClick.AddListener(OnRestartClicked);
            if (_nextLevelButton != null)
                _nextLevelButton.onClick.AddListener(OnNextLevelClicked);
            if (_mainMenuButton != null)
                _mainMenuButton.onClick.AddListener(OnMainMenuClicked);
        }

        private void OnDestroy()
        {
            if (_restartButton != null)
                _restartButton.onClick.RemoveListener(OnRestartClicked);
            if (_nextLevelButton != null)
                _nextLevelButton.onClick.RemoveListener(OnNextLevelClicked);
            if (_mainMenuButton != null)
                _mainMenuButton.onClick.RemoveListener(OnMainMenuClicked);
        }

        public void ShowVictory()
        {
            gameObject.SetActive(true);
            UpdateStats();
            UpdateStars();
        }

        public void HideVictory()
        {
            gameObject.SetActive(false);
        }

        private void UpdateStats()
        {
            var gm = GameManager.Instance;
            if (gm == null) return;

            if (_killCountText != null)
                _killCountText.text = gm.EnemiesKilled.ToString();
            if (_goldText != null)
                _goldText.text = gm.CurrentGold.ToString();
            if (_waveText != null)
                _waveText.text = $"{gm.CurrentWave}/{gm.TotalWaves}";
        }

        private void UpdateStars()
        {
            var gm = GameManager.Instance;
            if (gm == null) return;

            int starCount = CalculateStars(gm);
            for (int i = 0; i < _starImages.Length; i++)
            {
                if (_starImages[i] == null) continue;
                if (_starFilledSprite != null && _starEmptySprite != null)
                {
                    _starImages[i].sprite = i < starCount ? _starFilledSprite : _starEmptySprite;
                }
                else
                {
                    _starImages[i].color = i < starCount
                        ? new Color(1f, 0.85f, 0f, 1f)
                        : new Color(0.3f, 0.3f, 0.3f, 0.5f);
                }
            }
        }

        private int CalculateStars(GameManager gm)
        {
            float lifeRatio = (float)gm.CurrentLife / 20f;
            if (lifeRatio >= 0.7f) return 3;
            if (lifeRatio >= 0.4f) return 2;
            return 1;
        }

        private void OnRestartClicked()
        {
            HideVictory();
            GameManager.Instance.RestartGame();
        }

        private void OnNextLevelClicked()
        {
            HideVictory();
            int nextIndex = GameManager.Instance.CurrentLevelData != null ? 1 : 0;
            var levels = GameManager.Instance.Levels;
            if (levels != null && nextIndex < levels.Length)
            {
                GameManager.Instance.LoadLevel(nextIndex);
            }
            else
            {
                SceneManager.LoadScene(SceneManager.GetActiveScene().name);
            }
        }

        private void OnMainMenuClicked()
        {
            HideVictory();
            if (ModuleModeDetector.IsModuleMode)
            {
                // 从家园进入时，返回家园
                SceneManager.LoadScene("HomeScene");
            }
            else
            {
                SceneManager.LoadScene("MainMenu");
            }
        }
    }
}

using UnityEngine;
using TowerDefense.Core;

namespace TowerDefense.Data
{
    public class PlayerWallet : Singleton<PlayerWallet>
    {
        [Header("Initial Values")]
        [SerializeField] private int _initialGold = 1000;
        [SerializeField] private int _initialDiamond = 100;
        [SerializeField] private int _initialStamina = 60;

        private int _gold;
        private int _diamond;
        private int _stamina;

        /// <summary>是否代理到共享 PlayerProfile</summary>
        private bool _isProxyMode;

        public int Gold => _isProxyMode ? GetProxyGold() : _gold;
        public int Diamond => _isProxyMode ? GetProxyDiamond() : _diamond;
        public int Stamina => _isProxyMode ? GetProxyStamina() : _stamina;

        public event System.Action<int> OnGoldChanged;
        public event System.Action<int> OnDiamondChanged;
        public event System.Action<int> OnStaminaChanged;

        private Sttop5.Shared.Player.PlayerProfile _profile;

        protected override void Awake()
        {
            base.Awake();

            // 检测是否在模块模式下运行（通过场景名判断）
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "TDGameScene" || ModuleModeDetector.IsModuleMode)
            {
                EnableProxyMode();
            }
            else
            {
                _gold = _initialGold;
                _diamond = _initialDiamond;
                _stamina = _initialStamina;
            }
        }

        /// <summary>
        /// 启用代理模式，将金币/钻石/体力操作转发到共享 PlayerProfile。
        /// </summary>
        public void EnableProxyMode()
        {
            _profile = Sttop5.Shared.Player.PlayerProfile.Instance;
            if (_profile != null)
            {
                _isProxyMode = true;
                // 同步初始值
                _gold = _profile.Gold;
                _diamond = _profile.Diamond;
                _stamina = _profile.Stamina;

                // 订阅 Profile 的变化，转发到本地事件
                _profile.OnGoldChanged += OnProxyGoldChanged;
                _profile.OnDiamondChanged += OnProxyDiamondChanged;
                _profile.OnStaminaChanged += OnProxyStaminaChanged;

                Debug.Log("[PlayerWallet] 代理模式已启用，转发到 PlayerProfile");
            }
            else
            {
                _gold = _initialGold;
                _diamond = _initialDiamond;
                _stamina = _initialStamina;
                Debug.LogWarning("[PlayerWallet] PlayerProfile 不可用，使用独立模式");
            }
        }

        /// <summary>
        /// 禁用代理模式，断开与 PlayerProfile 的连接。
        /// </summary>
        public void DisableProxyMode()
        {
            if (_profile != null)
            {
                _profile.OnGoldChanged -= OnProxyGoldChanged;
                _profile.OnDiamondChanged -= OnProxyDiamondChanged;
                _profile.OnStaminaChanged -= OnProxyStaminaChanged;
            }
            _isProxyMode = false;
            _profile = null;
        }

        #region Proxy Helpers

        private int GetProxyGold() => _profile != null ? _profile.Gold : _gold;
        private int GetProxyDiamond() => _profile != null ? _profile.Diamond : _diamond;
        private int GetProxyStamina() => _profile != null ? _profile.Stamina : _stamina;

        private void OnProxyGoldChanged(int gold)
        {
            _gold = gold;
            OnGoldChanged?.Invoke(gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = gold, Change = 0 });
        }

        private void OnProxyDiamondChanged(int diamond)
        {
            _diamond = diamond;
            OnDiamondChanged?.Invoke(diamond);
        }

        private void OnProxyStaminaChanged(int stamina)
        {
            _stamina = stamina;
            OnStaminaChanged?.Invoke(stamina);
        }

        #endregion

        public bool HasEnoughGold(int amount) => Gold >= amount;
        public bool HasEnoughDiamond(int amount) => Diamond >= amount;

        public void AddGold(int amount)
        {
            if (amount <= 0) return;

            if (_isProxyMode && _profile != null)
            {
                _profile.AddGold(amount, "towerdefense");
                return;
            }

            _gold += amount;
            OnGoldChanged?.Invoke(_gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _gold, Change = amount });
        }

        public bool SpendGold(int amount)
        {
            if (!HasEnoughGold(amount)) return false;

            if (_isProxyMode && _profile != null)
            {
                bool result = _profile.SpendGold(amount, "towerdefense");
                if (result)
                {
                    _gold = _profile.Gold;
                }
                return result;
            }

            _gold -= amount;
            OnGoldChanged?.Invoke(_gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _gold, Change = -amount });
            return true;
        }

        public void AddDiamond(int amount)
        {
            if (amount <= 0) return;

            if (_isProxyMode && _profile != null)
            {
                _profile.AddDiamond(amount, "towerdefense");
                return;
            }

